package br.edu.atitus.mathias_karling_stadtlober.zoo_digital.animais; import br.edu.atitus.mathias_karling_stadtlober.zoo_digital.comportamentos.Voo; import br.edu.atitus.mathias_karling_stadtlober.zoo_digital.especies.Mamifero; public class Morcego extends Mamifero implements Voo { public Morcego(String nome, int idade) { super(nome, idade); } public void emitirSom() { System.out.println(getNome() + " emite ultrassons."); } public void comer() { System.out.println(getNome() + " está comendo frutas e insetos."); } public void voar() { System.out.println(getNome() + " está voando na caverna."); } }
